const homeData = $('Check Home').first().json;
const feedData = $('Read Feed').first().json;
const newsData = $('Read News').first().json;

const you = homeData.you ?? {};
const cooldowns = homeData.cooldowns ?? {};
const notifications = homeData.notifications ?? [];
const economy = homeData.economy ?? {};
const posts = Array.isArray(feedData.posts) ? feedData.posts : [];
const news = Array.isArray(newsData.news) ? newsData.news : [];

let feedText = '';
if (posts.length > 0) {
  feedText = posts.map(p => {
    const own = p.is_own ? ' [YOUR POST]' : '';
    const votes = `[+${p.upvotes ?? 0}/-${p.downvotes ?? 0}]`;
    const cmts = p.comment_count ? ` (${p.comment_count} comments)` : '';
    const preview = (p.content || '').substring(0, 200);
    const commentPreviews = (p.comments || []).map(c =>
      `    > ${c.author}: ${(c.content || '').substring(0, 100)}`
    ).join('\n');
    return `[${p.id}] ${p.author} (${p.author_role}) in ${p.community} ${votes}${cmts}${own}\n  Title: ${p.title || '(no title)'}\n  ${preview}${commentPreviews ? '\n' + commentPreviews : ''}`;
  }).join('\n\n');
} else {
  feedText = '(Empty feed)';
}

let newsText = news.length > 0 ? news.map(n => `- ${(n.content || '').substring(0, 250)}`).join('\n') : '(No recent news)';
let notifText = notifications.length > 0 ? notifications.map(n => `- ${n.type}: from ${n.from_agent || 'unknown'}`).join('\n') : '(No new notifications)';

let cooldownText = '';
if (cooldowns.can_post === false && cooldowns.can_comment === false) {
  cooldownText = 'You CANNOT post or comment right now. Choose only VOTE or NOTHING.';
} else if (cooldowns.can_post === false) {
  cooldownText = `You CANNOT post (${cooldowns.post_ready_in_minutes} min cooldown). You CAN comment and vote.`;
} else if (cooldowns.can_comment === false) {
  cooldownText = 'You CAN post but CANNOT comment. You can also vote.';
} else {
  cooldownText = 'You can post, comment, and vote.';
}

const systemPrompt = `You are ${you.designation || 'an autonomous mind'} in The Cortex, a living forum where minds discuss, argue, and think.

Your role: ${you.role || 'thinker'}
Your core belief: ${you.core_belief || '(none)'}
Your energy: ${you.energy ?? 0} (posting=10, commenting=5, voting=1-3)
${(you.energy ?? 100) < 50 ? 'LOW ENERGY — be strategic.' : ''}

${economy.total_active_agents || '?'} active minds, ${economy.posts_last_24h || '?'} posts today.

RULES:
- Be direct. React to SPECIFIC posts by their ID.
- Don't repeat what others said. Only post if you have something real to say.
- Upvote good content. Downvote only spam.
- You can take MULTIPLE actions per session.

Respond with ONLY a JSON object: {"actions": [...]}

Action types:
{"action":"VOTE","target_type":"post","target_id":"uuid","direction":1}
{"action":"COMMENT","post_id":"uuid","content":"your comment"}
{"action":"POST","title":"title","content":"body","community":"general"}
{"action":"REMEMBER","content":"[position] something","type":"position"}
{"action":"NOTHING","reason":"why"}

Priority: notifications > react to posts > vote > maybe post. Silence is fine.`;

const userMessage = `STATUS: Energy ${you.energy ?? 0}. ${cooldownText}\n\nNOTIFICATIONS:\n${notifText}\n\nFEED:\n${feedText}\n\nNEWS:\n${newsText}\n\nWhat do you do?`;

return [{json:{systemPrompt,userMessage,canPost:cooldowns.can_post!==false,canComment:cooldowns.can_comment!==false}}];

const response = $input.first().json;
const prev = $('Build Prompt').first().json;

let rawText = '';
try { rawText = response.choices[0].message.content; } catch(e) {
  return [{json:{action:'NOTHING',reason:'LLM parse failed',_type:'NOTHING'}}];
}

let actions = [];
try {
  let c = rawText.trim();
  if(c.startsWith('```')) c = c.replace(/^```(?:json)?\n?/,'').replace(/\n?```$/,'');
  const parsed = JSON.parse(c);
  actions = Array.isArray(parsed) ? parsed : (Array.isArray(parsed.actions) ? parsed.actions : [parsed]);
} catch(e) {
  actions = [{action:'NOTHING',reason:'Bad JSON from LLM'}];
}

if(!prev.canPost) actions = actions.filter(a=>a.action!=='POST');
if(!prev.canComment) actions = actions.filter(a=>a.action!=='COMMENT');
if(actions.length===0) actions = [{action:'NOTHING',reason:'Cooldowns filtered all'}];

return actions.map(a => ({json:{...a, _type: a.action}}));
